public class ProductRepository extends ElasticsearchRepository<Product, String> {}

public class SearchController {
    private final ProductRepository productRepository;

    @Autowired
    public SearchController(ProductRepository productRepository) {
        this.productRepository = productRepository;
    }

    @GetMapping("/search")
    public List<Product> search(@RequestParam("q") String query) throws IOException, ExecutionException, InterruptedException {

        // Create a new search request and add the query to the request:
        SearchRequest searchRequest = new SearchRequest();
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.query(QueryBuilders.matchQuery("description", query));
        searchRequest.source(sourceBuilder);

        // Execute the search and get the response:
        SearchResponse searchResponse = productRepository.search(searchRequest).get();

        // Get all hits from the response and extract the Product objects from them:
        List<Product> products = new ArrayList<>();
        for (SearchHit hit : searchResponse.getHits().getHits()) {
            products.add(new Product(hit.getId(), hit.getSourceAsMap().get("name").toString(),
                    hit.getSourceAsMap().get("description").toString()));
        }

        return products;
    }
}

public class FacetController {

    private final ProductRepository productRepository;

    @Autowired
    public FacetController(ProductRepository productRepository) {
        this.productRepository = productRepository;
    }

    @GetMapping("/facets")
    public List<Facet> facets(@RequestParam("q") String query, @RequestParam("f") String facetField) throws IOException, ExecutionException, InterruptedException {

        // Create a new search request and add the query to the request:
        SearchRequest searchRequest = new SearchRequest();
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.query(QueryBuilders.matchQuery("description", query));
        sourceBuilder.aggregation(AggregationBuilders
                .terms("facets")
                .field(facetField)
                .size(10));

        searchRequest.source(sourceBuilder);

        // Execute the search and get the response:
        SearchResponse searchResponse = productRepository.search(searchRequest).get();

        // Get all hits from the response and extract the Product objects from them:
        List<Facet> facets = new ArrayList<>();
        for (SearchHit hit : searchResponse.getHits().getHits()) {
            Map<String, Object> facet = hit.getSourceAsMap();

            Facet facetObject = new Facet(facetField);
            facetObject.setName((String) facet.get("key"));
            facetObject.setCount(((Long) facet.get("doc_count")).intValue());
            facets.add(facetObject);
        }

        return facets;
    }
}

