public class IndexController {

    private final ProductRepository productRepository;

    @Autowired
    public IndexController(ProductRepository productRepository) {
        this.productRepository = productRepository;
    }

    @GetMapping("/index")
    public void index() throws IOException, ExecutionException, InterruptedException {

        // Create a new search request and add the query to the request:
        SearchRequest searchRequest = new SearchRequest();
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.query(QueryBuilders.matchAllQuery());
        searchRequest.source(sourceBuilder);

        // Execute the search and get the response:
        SearchResponse searchResponse = productRepository.search(searchRequest).get();

        // Get all hits from the response and extract the Product objects from them:
        List<Product> products = new ArrayList<>();
        for (SearchHit hit : searchResponse.getHits().getHits()) {
            products.add(new Product(hit.getId(), hit.getSourceAsMap().get("name").toString(),
                    hit.getSourceAsMap().get("description").toString()));

            // Create a new index request and add the product to it:
            IndexRequest indexRequest = new IndexRequest();
            indexRequest.id(products.get(0).getId());
            indexRequest.source(new Gson().toJson(products), XContentType.JSON);

            // Execute the index request and get the response:
            IndexResponse indexResponse = productRepository.index(indexRequest).get();
        }
    }
}

